"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[9393],{16584:e=>{e.exports=JSON.parse('{"functions":[{"name":"new","desc":"Constructs a new `RoundInputHandler` for the given [RoundCharacterController].","params":[{"name":"controller","desc":"","lua_type":"RoundCharacterController"}],"returns":[{"desc":"","lua_type":"RoundInputHandler"}],"function_type":"static","source":{"line":97,"path":"src/Client/Classes/RoundInputHandler.luau"}},{"name":"Destroy","desc":"Cleans up all connections used by the input handler.","params":[],"returns":[],"function_type":"method","source":{"line":110,"path":"src/Client/Classes/RoundInputHandler.luau"}},{"name":"_init","desc":"Initializes the input handler with the given [RoundCharacterController], connecting it to [UserInputService] events.","params":[],"returns":[],"function_type":"method","private":true,"source":{"line":120,"path":"src/Client/Classes/RoundInputHandler.luau"}},{"name":"_onPostSimulation","desc":"Processes post-simulation updates, setting the mouse icon and behavior based on the current state of the input handler.\\nIf a tool is equipped, the tool\'s [ToolController.MouseIcon] is shown.","params":[],"returns":[],"function_type":"method","private":true,"source":{"line":188,"path":"src/Client/Classes/RoundInputHandler.luau"}}],"properties":[{"name":"_trove","desc":"The [Trove] used to manage the round input handler\'s connections.","lua_type":"Trove","private":true,"source":{"line":51,"path":"src/Client/Classes/RoundInputHandler.luau"}},{"name":"_controller","desc":"The [RoundCharacterController] the input handler handles input for.","lua_type":"RoundCharacterController","private":true,"source":{"line":57,"path":"src/Client/Classes/RoundInputHandler.luau"}},{"name":"_curTool","desc":"The currently equipped [ToolController].","lua_type":"ToolController?","private":true,"source":{"line":63,"path":"src/Client/Classes/RoundInputHandler.luau"}}],"types":[],"name":"RoundInputHandler","desc":"RoundInputHandler manages user input for a [RoundCharacterController], connecting player actions to tool usage \\nand gameplay interactions. It handles input events such as equipping tools, activating tool actions, and switching \\ntools. Additionally, it ensures the mouse behavior and icon are updated to reflect the player\'s current state.\\n\\n### Core Features:\\n- **Tool Management**: Listens for key presses to equip specific tools (e.g., Slingshot or Hammer) and routes mouse \\n  clicks to the active tool for primary or secondary actions.\\n- **Mouse Handling**: Dynamically adjusts the mouse icon and behavior based on whether a tool is equipped and \\n  gameplay conditions such as chat focus.\\n- **Input Event Integration**: Connects to [UserInputService] events to monitor and handle keyboard and mouse input.\\n\\n### Highlights:\\n- Uses [Trove] to manage connections, ensuring proper cleanup when the handler is destroyed.\\n- Reacts to the `ToolEquipped` and `ToolUnequipped` signals emitted by the associated [RoundCharacterController].\\n- Updates the mouse icon dynamically using the equipped [ToolController.MouseIcon] property.\\n\\nThe input handler automatically manages input connections and mouse behavior for the associated character controller.","realm":["Client"],"source":{"line":86,"path":"src/Client/Classes/RoundInputHandler.luau"}}')}}]);